const requiredFields = [
      { name: "plant_id", label: "Plant" },
      { name: "packing_no", label: "Packing No" },
      {
        name: "table_hu",
        label: "Handling Unit Table",
        isArray: true,
        arrayType: "object",
        arrayFields: [],
      },
    ];

return {
  required_fields: JSON.stringify(requiredFields),
  entry: JSON.stringify({{workflowparams:entry}})
}

let entry = {{workflowparams:entry}};
const saveAs = {{workflowparams:saveAs}}
let updatedTableHU = [];

for (const [index, huLineItem] of entry.table_hu.entries()) {
  huLineItem.plant_id = entry.plant_id || null;
  huLineItem.customer_id = entry.customer_id || [];
  huLineItem.organization_id = entry.organization_id;
}

if (saveAs === "Draft") {
  if(entry.packing_no_type !== -9999 && (
  !entry.packing_no || entry.packing_no === null || entry.packing_no === ''
)) {
  entry.packing_no = 'draft'
  }
} else {
  if (
  entry.packing_no_type !== -9999 &&
  (!entry.packing_no ||
    entry.packing_no === null ||
    entry.packing_no === "")
) {
  entry.packing_no = 'issued'
  }
}

return {
  table_hu: updatedTableHU,
  packing_no: entry.packing_no,
};

const data = {{workflowparams:entry}}
const packingMode = data.packing_mode;
const tableHU = {{node:code_node_7u6VSG8X.data.table_hu}} || [];
const tableItems = data.table_items || [];

// Calculate total item quantity (with safety checks)
data.total_item_qty = tableItems.reduce(
    (total, item) => total + (parseFloat(item.total_quantity) || 0),
    0
  );

// Calculate total HU count based on packing mode
if (packingMode === "Basic") {
    data.total_hu_count = tableHU.reduce(
      (total, item) => total + (parseInt(item.hu_quantity) || 0),
      0
    );
  } else {
    data.total_hu_count = tableHU.length;
  }

  // Count unique item codes (efficient approach)
data.total_item_count = new Set(
    tableItems.map((item) => item.item_code).filter(Boolean)
  ).size;

data.table_hu = tableHU

return {
  entry: data,
  entryId: data.id
}

const tableHU = {{workflowparams:entry.table_hu}} || [];
const tableItems = {{workflowparams:entry.table_items}} || [];

// Validate input data exists
if (tableHU.length === 0 || tableItems.length === 0) {
  return {
    fullyPacked: "false",
    message: "Missing HU or Item data. Please review and try again."
  };
}

// Calculate totals
const huTotalItemQuantity = tableHU.reduce((total, hu) => {
  return total + (hu.total_quantity || 0);
}, 0);

const itemTotalQuantity = tableItems.reduce((total, item) => {
  return total + (item.total_quantity || 0);
}, 0);

// Check if fully packed
const fullyPacked = huTotalItemQuantity === itemTotalQuantity;

if (!fullyPacked) {
  return {
    fullyPacked: "false",
    message: `Packing incomplete: HU total (${huTotalItemQuantity}) does not match item total (${itemTotalQuantity}). Please review and try again.`
  };
}

return {
  fullyPacked: "true"
};

const rawPackingData = {{node:add_node_PEwf0OYt.data}}
const packingData = rawPackingData[0]

return {
  packingData
}

const data = {{node:code_node_CYy1gmHf.data.entry}}
const tableItems = data.table_items || [];
const packingMode = data.packing_mode;

let uniqueSOIds
let uniqueSOLineIds

if (packingMode === "Basic") {
  //filter duplicated so_id
  uniqueSOIds = [...new Set(tableItems.map((item) => item.so_id))];

  //filter duplicated so_line_id
  uniqueSOLineIds = [...new Set(tableItems.map((item) => item.so_line_id)),
  ];
}

return {
  uniqueSOIds: uniqueSOIds,
  uniqueSOLineIds: uniqueSOLineIds
}

